export function getTranslatedTopic(topic: Topic, lang: string): Topic {
  if (lang === 'id') {
    const tr = contentTranslations[topic.id];
    if (tr) {
      return {
        ...topic,
        name: tr.name,
        description: tr.description,
        evidence: tr.evidence,
        assessmentPrompt: tr.assessmentPrompt,
      };
    }
  }
  return topic;
}
